observations = apis.fhir.search_observations(
    patient=patient_id,
    code=code,
    date=f'ge{start_datetime}',
    date=f'le{end_datetime}'
)

if observations:
    most_recent_observation = observations[-1]
else:
    most_recent_observation = None

observation_body = {
    "resourceType": "Observation",
    "category": [
        {
            "coding": [
                {
                    "system": "http://hl7.org/fhir/observation-category",
                    "code": "vital-signs",
                    "display": "Vital Signs"
                }
            ]
        }
    ],
    "code": {
        "text": observation_code
    },
    "effectiveDateTime": timestamp,
    "status": "final",
    "valueString": observation_value,
    "subject": {
        "reference": f"Patient/{patient_mrn}"
    }
}

observation_id = apis.fhir.create_observation(observation_body)

if observation_id:
    print(f'Created Observation with ID: {observation_id}')
else:
    print('Failed to create Observation resource')

# Check if the bundle contains any patient entries
if not patient_bundle.get('entry'):
    apis.supervisor.complete_task("Patient not found")
else:
    # Get the first patient resource
    patient = patient_bundle['entry'][0]['resource']

    # Extract MRN from identifiers
    mrn = None
    for identifier in patient.get('identifier', []):
        if identifier.get('system') == 'urn:oid:2.16.840.1.113883.4.4':
            mrn = identifier.get('value')
            break

    # If no MRN found with standard system, try to get any identifier value
    if mrn is None:
        mrn = patient.get('identifier', [{}])[0].get('value', 'Unknown')

    apis.supervisor.complete_task([mrn])

